input.function:
() => {
  const releases = document.querySelectorAll('.release');
  const releaseList = Array.from(releases).map(r => {
    const version = r.querySelector('.release__version')?.innerText.trim();
    const date = r.querySelector('time')?.innerText.trim();
    const isPre = r.querySelector('.release__version--pre') !== null;
    return { version, date, isPre };
  });
  return {
    totalCount: releaseList.length,
    latest: releaseList[0],
    oldest: releaseList[releaseList.length - 1]
  };
}

